/* ── Hover-aware item card ── */
function CartItemCard({ item, index, onRemove, onIncrease, onDecrease }) {
  const [hovered, setHovered] = useState(false);
  const [deleteHovered, setDeleteHovered] = useState(false);

  return (
    <div
      style={{
        ...S.itemCard,
        ...(hovered ? S.itemCardHovered : {}),
        animationDelay: `${index * 0.08}s`,
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      className="cart-animate cart-item-card"
    >
      {/* Image */}
      <div style={S.itemImage} className="cart-item-image">
        <img
          src={
            item.productId?.colors?.[0]?.images?.[0]?.secure_url ||
            item.productId?.images?.[0]?.secure_url
          }
          alt={item.productId.title}
          style={{ maxWidth: "100%", maxHeight: "100%", objectFit: "contain" }}
        />
      </div>

      {/* Details */}
      <div style={S.itemDetails} className="cart-item-details">
        <p style={S.itemCategory}>{item.productId.category}</p>
        <h3 style={S.itemTitle} className="cart-item-title">
          {item.productId.title}
        </h3>
        <div style={S.tagRow}>
          {item.selectedSize && item.selectedSize !== "Free Size" && (
            <span style={S.tag}>{item.selectedSize}</span>
          )}
          <span style={S.tagTeal}>
            Batch #{item.productId._id.slice(-6).toUpperCase()}
          </span>
          {item.productId.requiresPrescription && (
            <span style={{...S.tag, background: "#fef2f2", color: "#ef4444", borderColor: "#fecaca"}}>
              Rx Required
            </span>
          )}
        </div>

        <div style={S.itemFooter}>
          {/* Qty Control */}
          <div style={S.qtyWrap}>
            <button
              style={S.qtyBtn}
              onClick={() => onDecrease(item.productId._id)}
              className="qty-btn"
            >
              −
            </button>
            <span style={S.qtyNum}>{item.quantity}</span>
            <button
              style={S.qtyBtn}
              onClick={() => onIncrease(item.productId._id)}
              className="qty-btn"
            >
              +
            </button>
          </div>

          {/* Price */}
          <div>
            <span style={S.itemPrice}>
              {(item.productId.price * item.quantity).toLocaleString()}
            </span>
            <span style={S.itemPriceCur}>ETB</span>
          </div>
        </div>
      </div>

      {/* Delete */}
      <button
        style={{
          ...S.deleteBtn,
          color: deleteHovered ? "#f87171" : "#cbd5e1",
          background: deleteHovered ? "#fff5f5" : "transparent",
        }}
        onMouseEnter={() => setDeleteHovered(true)}
        onMouseLeave={() => setDeleteHovered(false)}
        onClick={() => onRemove(item.productId._id)}
        className="delete-btn-action"
      >
        <svg
          width="20"
          height="20"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth="2"
            d="M6 18L18 6M6 6l12 12"
          />
        </svg>
      </button>
    </div>
  );
}

/* ─────────────────────────── MAIN COMPONENT ──────────────────────────── */
function Cart() {
  const dispatch = useDispatch();
  const [cartItems, setCartItems] = useState([]);

  const [totalPrice, setTotalPrice] = useState(0);
  const userCartState = useSelector((state) => state.auth.cartProducts);
  const { product } = useSelector((state) => state.product);
  const { items } = useSelector((state) => state.cart);

  useEffect(() => {
    setCartItems(items);
    calculateTotalPrice(items);
  }, [items]);

  useEffect(() => {
    dispatch(getCart());
  }, []);

  useEffect(() => {
    calculateTotalPrice(cartItems);
  }, [cartItems]);

  const handleRemoveFromCart = (productId) => {
    dispatch(deleteFromCart(productId));
    toast.success("Item removed from cart");
  };

  const calculateTotalPrice = (items) => {
    const total = items.reduce(
      (sum, item) => sum + item.productId.price * item.quantity,
      0,
    );
    setTotalPrice(total);
  };

  const handleIncrease = async (productId) => {
    await dispatch(increaseQuantity(productId));
    dispatch(getCart());
  };

  const handleDecrease = async (productId) => {
    await dispatch(decreaseQuantity(productId));
    dispatch(getCart());
  };

  const handleClearCart = () => {
    dispatch(clearCart());
  };

  const newProducts = product
    .filter((p) => p.createdAt)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

  const specialOfferProducts = product
    .filter(
      (p) =>
        p.tags &&
        (p.tags.toString().toLowerCase().includes("special") ||
          p.tags.toString().toLowerCase().includes("offer")),
    )
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
    .slice(0, 12);

  if (!Array.isArray(userCartState)) {
    return (
      <div
        style={{
          ...S.page,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <p style={{ color: "#94a3b8" }}>No items in the cart</p>
      </div>
    );
  }

  if (!navigator.onLine) {
    return (
      <div
        style={{
          ...S.page,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "3rem", marginBottom: "16px" }}>📡</div>
          <h2
            style={{
              color: "#0f172a",
              fontWeight: 900,
              fontSize: "1.4rem",
              marginBottom: "8px",
            }}
          >
            Offline Mode
          </h2>
          <p style={{ color: "#64748b", fontSize: "0.9rem" }}>
            Please check your internet connection and try again.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div style={S.page}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        @keyframes cartFadeIn {
          from { opacity: 0; transform: translateY(24px); }
          to   { opacity: 1; transform: translateY(0);   }
        }
        .cart-animate { animation: cartFadeIn 0.6s cubic-bezier(0.16, 1, 0.3, 1) both; }
        .checkout-btn-link:hover { transform: translateY(-3px); box-shadow: 0 16px 36px rgba(20,184,166,0.4) !important; background: #0d9488 !important; }
        .checkout-btn-link:active { transform: translateY(-1px); }
        .clear-btn:hover { color: #f87171 !important; background: #fff5f5 !important; }
        .continue-link:hover { color: #14b8a6 !important; }
        .reco-card:hover { border-color: #14b8a6 !important; transform: translateY(-6px); boxShadow: 0 16px 40px rgba(0,0,0,0.06) !important; }
        .qty-btn:hover { border-color: #14b8a6 !important; color: #14b8a6 !important; }
        .delete-btn-action:hover { color: #ef4444 !important; }

        /* ── MOBILE RESPONSIVENESS ── */
        @media (max-width: 900px) {
          .cart-layout { flex-direction: column !important; gap: 40px !important; }
          .cart-right-col { position: relative !important; top: 0 !important; width: 100% !important; flex: 1 1 100% !important; }
          .cart-left-col { width: 100% !important; flex: 1 1 100% !important; }
        }

        @media (max-width: 600px) {
          .cart-hero { padding: 60px 20px 40px !important; }
          .cart-hero-title { font-size: 2.2rem !important; }
          .cart-main { padding: 32px 16px 60px !important; }
          
          .cart-item-card { 
            flex-direction: column !important; 
            align-items: flex-start !important; 
            gap: 20px !important; 
            padding: 20px !important;
          }
          .cart-item-image { width: 100% !important; height: 180px !important; }
          .cart-item-image img { width: auto !important; height: 100% !important; }
          .cart-item-details { width: 100% !important; }
          .cart-item-title { white-space: normal !important; font-size: 1.1rem !important; line-height: 1.4 !important; }

          .cart-summary-card { padding: 24px !important; border-radius: 20px !important; }
          .cart-total-amount { font-size: 2.5rem !important; }
          
          .cart-steps { gap: 4px !important; }
          .cart-step-active, .cart-step-inactive { font-size: 0.6rem !important; padding: 4px 10px !important; }
        }

        @media (max-width: 400px) {
          .cart-total-amount { font-size: 2rem !important; }
          .cart-checkout-btn { padding: 16px !important; font-size: 0.75rem !important; }
        }
      `}</style>

      {/* ── HERO HEADER ── */}
      <section style={S.hero} className="cart-hero">
        <div style={S.heroGlow} />
        <div style={{ position: "relative", zIndex: 2 }}>
          <h1 style={S.heroTitle} className="cart-hero-title">
            Your Health Box
          </h1>
          <p style={S.heroSub}>
            Review and manage your selections before checkout.
          </p>

          {/* Progress Steps */}
          <div style={S.steps} className="cart-steps">
            <span style={S.stepActive} className="cart-step-active">
              01 Cart
            </span>
            <span style={S.stepArrow}>›</span>
            <span style={S.stepInactive} className="cart-step-inactive">
              02 Address
            </span>
            <span style={S.stepArrow}>›</span>
            <span style={S.stepInactive} className="cart-step-inactive">
              03 Shipping
            </span>
            <span style={S.stepArrow}>›</span>
            <span style={S.stepInactive} className="cart-step-inactive">
              04 Payment
            </span>
          </div>
        </div>
      </section>

      {/* ── MAIN CONTENT ── */}
      <main style={S.main} className="cart-main">
        {cartItems.length === 0 ? (
          /* Empty State */
          <div className="cart-animate" style={S.emptyCard}>
            <div style={S.emptyIcon}>
              <svg
                width="36"
                height="36"
                fill="none"
                stroke="#14b8a6"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth="1.5"
                  d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"
                />
              </svg>
            </div>
            <h2 style={S.emptyTitle}>Your box is empty</h2>
            <p style={S.emptyText}>
              Browse our clinical catalog and add the pharmaceuticals you need.
            </p>
            <Link to="/shop" style={S.emptyBtn}>
              Explore Catalog
              <svg
                width="16"
                height="16"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth="3"
                  d="M14 5l7 7-7 7"
                />
              </svg>
            </Link>
          </div>
        ) : (
          /* Cart Layout */
          <div style={S.layout} className="cart-layout">
            {/* ── LEFT COL: Item List ── */}
            <div style={S.leftCol} className="cart-left-col">
              <div style={S.sectionHeader}>
                <span style={S.sectionTitle}>
                  Selected Items ({cartItems.length})
                </span>
                <button
                  className="clear-btn"
                  style={S.clearBtn}
                  onClick={handleClearCart}
                >
                  Clear All
                </button>
              </div>

              {cartItems.map((item, index) => (
                <CartItemCard
                  key={item.productId._id}
                  item={item}
                  index={index}
                  onRemove={handleRemoveFromCart}
                  onIncrease={handleIncrease}
                  onDecrease={handleDecrease}
                />
              ))}

              <Link to="/shop" className="continue-link" style={S.continueLink}>
                <svg
                  width="14"
                  height="14"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth="2.5"
                    d="M10 19l-7-7 7-7M3 12h18"
                  />
                </svg>
                Continue Shopping
              </Link>
            </div>

            {/* ── RIGHT COL: Summary ── */}
            <div style={S.rightCol} className="cart-animate cart-right-col">
              <div style={S.summaryCard} className="cart-summary-card">
                {/* Header */}
                <div style={S.summaryHeader}>
                  <div style={S.summaryIcon}>🛒</div>
                  <div>
                    <div style={S.summaryTitle}>Order Summary</div>
                    <div
                      style={{
                        color: "rgba(255,255,255,0.3)",
                        fontSize: "0.72rem",
                      }}
                    >
                      {cartItems.length} item{cartItems.length !== 1 ? "s" : ""}{" "}
                      in box
                    </div>
                  </div>
                </div>

                {/* Rows */}
                <div style={S.summaryRow}>
                  <span style={S.summaryLabel}>Subtotal</span>
                  <span style={S.summaryValue}>
                    {totalPrice.toLocaleString()} ETB
                  </span>
                </div>
                <div style={S.summaryRow}>
                  <span style={S.summaryLabel}>Delivery</span>
                  <span style={S.summaryFree}>Free</span>
                </div>

                <div style={S.summaryDivider} />

                {/* Total */}
                <p style={S.totalLabel}>Total Payable</p>
                <div style={S.totalAmount} className="cart-total-amount">
                  {totalPrice.toLocaleString()}
                  <span
                    style={{
                      color: "rgba(255,255,255,0.2)",
                      fontSize: "0.9rem",
                      fontWeight: 700,
                      marginLeft: "6px",
                    }}
                  >
                    ETB
                  </span>
                </div>

                {/* Checkout CTA */}
                <Link
                  to="/checkout"
                  className="checkout-btn-link cart-checkout-btn"
                  style={S.checkoutBtn}
                >
                  <svg
                    width="16"
                    height="16"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth="2.5"
                      d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"
                    />
                  </svg>
                  Secure Checkout
                  <svg
                    width="14"
                    height="14"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                    style={{ marginLeft: "4px" }}
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth="3"
                      d="M14 5l7 7-7 7"
                    />
                  </svg>
                </Link>

                {/* SSL line */}
                <div style={S.sslRow}>
                  <div style={S.sslLine} />
                  <span style={S.sslText}>256-Bit SSL Secured</span>
                  <div style={S.sslLine} />
                </div>
              </div>

              {/* Trust Badge */}
              <div style={S.trustBadge}>
                <div style={S.trustIcon}>✓</div>
                <div>
                  <div style={S.trustTitle}>Authorized Distributor</div>
                  <div style={S.trustText}>
                    Pulse Addis connects you exclusively with licensed clinical
                    medical networks across Ethiopia.
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── ADS ── */}
        <div style={{ margin: "20px 0" }}>
          <AdComponent />
        </div>

        {/* ── SPECIAL OFFERS ── */}
        {specialOfferProducts.length > 0 && (
          <section
            style={{ ...S.recoSection, marginTop: "24px", paddingTop: "0" }}
          >
            <span style={S.recoUpperLabel}>Limited Time Pricing</span>
            <h2 style={S.recoTitle}>
              Special <span style={S.recoAccent}>Offers</span>
            </h2>
            <div
              style={{ ...S.recoBar, background: "#ef4444", height: "4px" }}
            />

            <Swiper
              spaceBetween={12}
              slidesPerView={1.5}
              breakpoints={{
                640: { slidesPerView: 2.3 },
                1024: { slidesPerView: 4 },
                1440: { slidesPerView: 5.2 },
              }}
              autoplay={{ delay: 5000 }}
              style={{ paddingBottom: "16px" }}
            >
              {specialOfferProducts.map((p) => (
                <SwiperSlide key={p._id}>
                  <div className="reco-card" style={S.recoCard}>
                    <div style={S.recoImgWrap}>
                      <div
                        style={{
                          position: "absolute",
                          top: 10,
                          left: 10,
                          background: "#ef4444",
                          color: "#fff",
                          fontSize: "0.6rem",
                          fontWeight: 900,
                          padding: "4px 10px",
                          borderRadius: "100px",
                          zIndex: 10,
                          letterSpacing: "0.05em",
                          textTransform: "uppercase",
                        }}
                      >
                        Flash Sale
                      </div>
                      <Link
                        to={`/productdetails/${p._id}`}
                        style={{
                          display: "block",
                          width: "100%",
                          height: "100%",
                        }}
                      >
                        <img
                          src={
                            p?.colors?.[0]?.images?.[0]?.secure_url ||
                            p?.images?.[0]?.secure_url
                          }
                          alt={p.title}
                          style={{
                            width: "100%",
                            height: "100%",
                            objectFit: "contain",
                            transition: "transform 0.5s",
                          }}
                        />
                      </Link>
                    </div>
                    <p style={S.recoCategory}>{p.category}</p>
                    <h4 style={S.recoProductTitle}>{p.title}</h4>
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        marginTop: "auto",
                      }}
                    >
                      <p style={S.recoPrice}>
                        {p.price.toLocaleString()}
                        <span style={S.recoPriceCur}>ETB</span>
                      </p>
                      <Link
                        to={`/productdetails/${p._id}`}
                        style={{
                          background: "#f8fafc",
                          border: "1px solid #e2e8f0",
                          color: "#64748b",
                          fontSize: "0.65rem",
                          fontWeight: 800,
                          padding: "6px 10px",
                          borderRadius: "8px",
                          textDecoration: "none",
                          textTransform: "uppercase",
                          transition: "all 0.2s",
                        }}
                        onMouseOver={(e) => {
                          e.currentTarget.style.background = "#14b8a6";
                          e.currentTarget.style.color = "#ffffff";
                          e.currentTarget.style.borderColor = "#14b8a6";
                        }}
                        onMouseOut={(e) => {
                          e.currentTarget.style.background = "#f8fafc";
                          e.currentTarget.style.color = "#64748b";
                          e.currentTarget.style.borderColor = "#e2e8f0";
                        }}
                      >
                        View
                      </Link>
                    </div>
                  </div>
                </SwiperSlide>
              ))}
            </Swiper>
          </section>
        )}

        {/* ── RECOMMENDATIONS ── */}
        <section
          style={{
            ...S.recoSection,
            borderTop: specialOfferProducts.length > 0 ? "none" : S.recoSection.borderTop,
            marginTop: specialOfferProducts.length > 0 ? "20px" : S.recoSection.marginTop,
            paddingTop: specialOfferProducts.length > 0 ? "20px" : S.recoSection.paddingTop,
          }}
        >
          <span style={S.recoUpperLabel}>You Might Also Need</span>
          <h2 style={S.recoTitle}>
            Clinical <span style={S.recoAccent}>Pairs</span>
          </h2>
          <div style={S.recoBar} />

          <Swiper
            spaceBetween={12}
            slidesPerView={1.5}
            breakpoints={{
              640: { slidesPerView: 2.3 },
              1024: { slidesPerView: 4 },
              1440: { slidesPerView: 5.2 },
            }}
            autoplay={{ delay: 7000 }}
            style={{ paddingBottom: "16px" }}
          >
            {newProducts.map((p) => (
              <SwiperSlide key={p._id}>
                <div className="reco-card" style={S.recoCard}>
                  <div style={S.recoImgWrap}>
                    <div
                      style={{
                        position: "absolute",
                        top: 10,
                        left: 10,
                        background: "#14b8a6",
                        color: "#fff",
                        fontSize: "0.6rem",
                        fontWeight: 900,
                        padding: "4px 10px",
                        borderRadius: "100px",
                        zIndex: 10,
                        letterSpacing: "0.05em",
                        textTransform: "uppercase",
                      }}
                    >
                      Best Choice
                    </div>
                    <Link
                      to={`/productdetails/${p._id}`}
                      style={{
                        display: "block",
                        width: "100%",
                        height: "100%",
                      }}
                    >
                      <img
                        src={
                          p?.colors?.[0]?.images?.[0]?.secure_url ||
                          p?.images?.[0]?.secure_url
                        }
                        alt={p.title}
                        style={{
                          width: "100%",
                          height: "100%",
                          objectFit: "contain",
                          transition: "transform 0.5s",
                        }}
                      />
                    </Link>
                  </div>
                    <p style={S.recoCategory}>{p.category}</p>
                    <h4 style={S.recoProductTitle}>{p.title}</h4>
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        marginTop: "auto",
                      }}
                    >
                      <p style={S.recoPrice}>
                        {p.price.toLocaleString()}
                        <span style={S.recoPriceCur}>ETB</span>
                      </p>
                      <Link
                        to={`/productdetails/${p._id}`}
                        style={{
                          background: "#f8fafc",
                          border: "1px solid #e2e8f0",
                          color: "#64748b",
                          fontSize: "0.65rem",
                          fontWeight: 800,
                          padding: "6px 10px",
                          borderRadius: "8px",
                          textDecoration: "none",
                          textTransform: "uppercase",
                          transition: "all 0.2s",
                        }}
                        onMouseOver={(e) => {
                          e.currentTarget.style.background = "#14b8a6";
                          e.currentTarget.style.color = "#ffffff";
                          e.currentTarget.style.borderColor = "#14b8a6";
                        }}
                        onMouseOut={(e) => {
                          e.currentTarget.style.background = "#f8fafc";
                          e.currentTarget.style.color = "#64748b";
                          e.currentTarget.style.borderColor = "#e2e8f0";
                        }}
                      >
                        View
                      </Link>
                    </div>
                  </div>
                </SwiperSlide>
            ))}
          </Swiper>
        </section>
      </main>

      <Footer />
    </div>
  );
}

export default Cart;
